174	    const onVolume = item?.dataset.action === "volume";
175	    switch (e.key) {
176	      case "ArrowUp": case "w": case "W": setSel(sel - 1); break;
177	      case "ArrowDown": case "s": case "S": setSel(sel + 1); break;
178	      case "Enter": case " ": activate(item); break;
179	      case "Escape": back(); break;
180	      case "ArrowLeft":
181	        if (!onVolume) return;
182	        setVolume(Number(volume.value) - 0.05);
183	        break;
184	      case "ArrowRight":
185	        if (!onVolume) return;
186	        setVolume(Number(volume.value) + 0.05);
187	        break;
188	      default: return;
189	    }
190	    e.preventDefault();
191	  }
192	  window.addEventListener("keydown", onKey);
193	
194	  for (const el of root.querySelectorAll(".ts-item")) {
195	    el.addEventListener("mouseenter", () => {
196	      const idx = items.indexOf(el);
197	      if (idx >= 0) setSel(idx);
198	    });
199	    el.addEventListener("click", (e) => {
200	      if (e.target === volume) return; // slider drag, not a menu pick
201	      const idx = items.indexOf(el);
202	      if (idx >= 0) setSel(idx);
203	      activate(el);
204	    });
205	  }
