#title-screen {
  position: absolute;
  inset: 0;
  z-index: 35;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  pointer-events: auto;
  background: radial-gradient(ellipse at 50% 44%, rgba(2, 4, 10, 0.55), rgba(2, 4, 10, 0.85));
