1	// Title screen — the arcade boot menu shown over the orbit view on first
2	// load. START GAME dismisses it; OPTIONS holds CONTROLS and SOUND. Sound
3	// drives the existing #audio-panel controls (the canonical music state) so
4	// this menu and the in-game panel can never disagree.
5	// The opening story — an unnamed storybook narrator (the Bug Bash register):
6	// third person about the world, then the last beat turns to the player with
7	// the goal. Plain words on purpose; no idioms, no jargon.
8	const STORY_BEATS = [
9	  "For a long time, the old world was enough. People wrote code there, and every line had a place to stay.",
10	  "Then humans and AI agents started building side by side. You loved it: more help, more ideas, and more work than one person could watch.",
11	  "But the old world was made for humans only. As your five subagent friends joined you, it began to feel too small.",
12	  "So you left in your own spaceship, searching for a world with space for all of you. Before you found it, the ship broke and crashed on a strange planet.",
13	  "Its memory fell in pieces across one small island. Bring it back. Wake your friends. Fix the ship - and fly again.",
14	];
15	
16	export function createTitleScreen({ onStart } = {}) {
17	  const root = document.getElementById("title-screen");
18	  const screens = {
19	    main: document.getElementById("ts-main"),
20	    options: document.getElementById("ts-options"),
21	    controls: document.getElementById("ts-controls"),
22	    display: document.getElementById("ts-display"),
23	    sound: document.getElementById("ts-sound"),
24	  };
25	  const parentOf = {
26	    options: "main",
27	    controls: "options",
28	    display: "options",
29	    sound: "options",
30	  };
31	  const story = document.getElementById("ts-story");
32	  const storyText = document.getElementById("ts-story-text");
33	  const storyNext = document.getElementById("ts-story-next");
34	
35	  const bgm = document.getElementById("bgm");
36	  const audioToggle = document.getElementById("audio-toggle");
37	  const audioVolume = document.getElementById("audio-volume");
38	  const musicState = document.getElementById("ts-music-state");
39	  const volume = document.getElementById("ts-volume");
40	  const volumePct = document.getElementById("ts-volume-pct");
41	  const tvState = document.getElementById("ts-tv-state");
42	
43	  // The TV effect (scanlines + vignette) is on by default; the choice is
44	  // remembered between visits.
45	  const TV_KEY = "pf-tv-effect";
46	  document.body.classList.toggle("tv-on", localStorage.getItem(TV_KEY) !== "off");
47	
48	  function syncDisplay() {
49	    const on = document.body.classList.contains("tv-on");
50	    tvState.textContent = on ? "ON" : "OFF";
51	    tvState.classList.toggle("is-off", !on);
52	  }
53	
54	  function toggleTv() {
55	    const on = !document.body.classList.contains("tv-on");
56	    document.body.classList.toggle("tv-on", on);
57	    localStorage.setItem(TV_KEY, on ? "on" : "off");
58	    syncDisplay();
59	  }
60	
61	  let active = false;
62	  let screenName = "main";
63	  let items = [];
64	  let sel = 0;
65	  let storyBeat = -1; // -1 = not in the story; otherwise index into STORY_BEATS
66	
67	  function syncSound() {
68	    if (!bgm) return;
69	    const playing = !bgm.paused;
70	    musicState.textContent = playing ? "ON" : "OFF";
71	    musicState.classList.toggle("is-off", !playing);
72	    volume.value = String(bgm.volume);
73	    volumePct.textContent = `${Math.round(bgm.volume * 100)}%`;
74	  }
75	  bgm?.addEventListener("play", syncSound);
76	  bgm?.addEventListener("pause", syncSound);
77	  bgm?.addEventListener("volumechange", syncSound);
78	
79	  function setVolume(v) {
80	    const clamped = Math.min(1, Math.max(0, v));
81	    // reflect immediately — the bgm volumechange event arrives async, too
82	    // late for a rapid second keypress to read the fresh value
83	    volume.value = String(clamped);
84	    volumePct.textContent = `${Math.round(clamped * 100)}%`;
85	    if (audioVolume) {
86	      // route through the in-game slider so its handler applies + reflects it
87	      audioVolume.value = String(clamped);
88	      audioVolume.dispatchEvent(new Event("input"));
89	    } else if (bgm) {
90	      bgm.volume = clamped;
91	    }
92	  }
93	
94	  function toggleMusic() {
95	    if (audioToggle) audioToggle.click();
96	    else if (bgm) bgm.paused ? bgm.play().catch(() => {}) : bgm.pause();
97	  }
98	
99	  function setSel(i) {
100	    if (!items.length) return;
101	    sel = (i + items.length) % items.length;
102	    items.forEach((el, idx) => el.classList.toggle("is-selected", idx === sel));
103	  }
104	
105	  function setScreen(name) {
106	    screenName = name;
107	    for (const [key, el] of Object.entries(screens)) {
108	      el.classList.toggle("hidden", key !== name);
109	    }
110	    items = [...screens[name].querySelectorAll(".ts-item")];
111	    setSel(0);
112	    if (name === "sound") syncSound();
113	    if (name === "display") syncDisplay();
114	  }
115	
116	  function back() {
117	    if (parentOf[screenName]) setScreen(parentOf[screenName]);
118	  }
119	
120	  function startStory() {
121	    storyBeat = -1;
122	    root.classList.add("is-story");
123	    for (const el of Object.values(screens)) el.classList.add("hidden");
124	    story.classList.remove("hidden");
125	    nextBeat();
126	  }
127	
128	  function nextBeat() {
129	    storyBeat += 1;
130	    if (storyBeat >= STORY_BEATS.length) {
131	      finishStory();
132	      return;
133	    }
134	    storyText.textContent = STORY_BEATS[storyBeat];
135	    storyNext.textContent = storyBeat === STORY_BEATS.length - 1 ? "to begin" : "to continue";
136	    // retrigger the fade-in for each beat
137	    storyText.classList.remove("beat-in");
138	    void storyText.offsetWidth;
139	    storyText.classList.add("beat-in");
140	  }
141	
142	  function finishStory() {
143	    storyBeat = -1;
144	    story.classList.add("hidden");
145	    // keep .is-story on through the leaving fade so the logo/tagline stay
146	    // hidden — otherwise they flash back in during the 650ms fade-out.
147	    // show() clears it on the next boot.
148	    hide();
149	    onStart?.();
150	  }
151	
152	  function activate(el) {
153	    switch (el?.dataset.action) {
154	      case "start": startStory(); break;
155	      case "options": setScreen("options"); break;
156	      case "controls": setScreen("controls"); break;
157	      case "display": setScreen("display"); break;
158	      case "sound": setScreen("sound"); break;
159	      case "music-toggle": toggleMusic(); break;
160	      case "tv-toggle": toggleTv(); break;
161	      case "back": back(); break;
162	    }
163	  }
164	
165	  function onKey(e) {
166	    if (!active) return;
167	    if (storyBeat >= 0) {
168	      // in the story: Space/Enter advance, Esc skips straight to the game
169	      if (e.key === " " || e.key === "Enter") nextBeat();
170	      else if (e.key === "Escape") finishStory();
171	      else return;
172	      e.preventDefault();
173	      return;
174	    }
175	    const item = items[sel];
176	    const onVolume = item?.dataset.action === "volume";
177	    switch (e.key) {
178	      case "ArrowUp": case "w": case "W": setSel(sel - 1); break;
179	      case "ArrowDown": case "s": case "S": setSel(sel + 1); break;
180	      case "Enter": case " ": activate(item); break;
181	      case "Escape": back(); break;
182	      case "ArrowLeft":
183	        if (!onVolume) return;
184	        setVolume(Number(volume.value) - 0.05);
185	        break;
186	      case "ArrowRight":
187	        if (!onVolume) return;
188	        setVolume(Number(volume.value) + 0.05);
189	        break;
190	      default: return;
191	    }
192	    e.preventDefault();
193	  }
194	  window.addEventListener("keydown", onKey);
195	
196	  for (const el of root.querySelectorAll(".ts-item")) {
197	    el.addEventListener("mouseenter", () => {
198	      const idx = items.indexOf(el);
199	      if (idx >= 0) setSel(idx);
200	    });
